import Vue from 'vue'
import Vuex from 'vuex'
import axios from 'axios'

Vue.use(Vuex)

const API_URL = 'http://localhost:3000/api'

export default new Vuex.Store({
  state: {
    trimestre: 'Q1',
    salesData: {},   
    users: [],       
    loading: false,
    error: null,
    // Auth State
    user: JSON.parse(localStorage.getItem('user')) || null,
    token: localStorage.getItem('token') || null
  },

  getters: {
    isAuthenticated: state => !!state.token,
    userRole: state => state.user ? state.user.role : null,
    userName: state => state.user ? state.user.name : 'Invitado',

    currentData: state => state.salesData[state.trimestre] || {
      kpis: { total: 0, orders: 0, ticket: 0, metaPct: 0 },
      months: [],
      ventas: [],
      metas: [],
      regiones: [],
      vendedores: []
    },
    kpis: (state, getters) => getters.currentData.kpis,
    chartData: (state, getters) => ({
      months: getters.currentData.months,
      ventas: getters.currentData.ventas,
      metas: getters.currentData.metas
    }),
    regiones: (state, getters) => getters.currentData.regiones,
    vendedores: (state, getters) => getters.currentData.vendedores,

    vendedoresConEstado: (state, getters) =>
      getters.vendedores.map(v => ({
        ...v,
        pct: v.meta > 0 ? Math.round((v.ventas / v.meta) * 100) : 0,
        estado: v.ventas >= v.meta ? 'green' : v.ventas >= v.meta * 0.85 ? 'amber' : 'red'
      })),

    topVendedor: (state, getters) =>
      getters.vendedores.length > 0
        ? [...getters.vendedores].sort((a, b) => b.ventas - a.ventas)[0]
        : { name: '...', ventas: 0 }
  },

  mutations: {
    SET_AUTH(state, { user, token }) {
      state.user = user
      state.token = token
      localStorage.setItem('user', JSON.stringify(user))
      localStorage.setItem('token', token)
    },
    LOGOUT(state) {
      state.user = null
      state.token = null
      localStorage.removeItem('user')
      localStorage.removeItem('token')
    },
    SET_TRIMESTRE(state, trimestre) {
      state.trimestre = trimestre
    },
    SET_SALES_DATA(state, { quarter, data }) {
      Vue.set(state.salesData, quarter, data)
    },
    SET_USERS(state, users) {
      state.users = users
    },
    SET_LOADING(state, value) {
      state.loading = value
    },
    SET_ERROR(state, error) {
      state.error = error
    }
  },

  actions: {
    async login({ commit }, credentials) {
      commit('SET_LOADING', true)
      commit('SET_ERROR', null)
      try {
        const response = await axios.post(`${API_URL}/auth/login`, credentials)
        commit('SET_AUTH', response.data)
        return response.data
      } catch (error) {
        const msg = error.response?.data?.error || 'Error al iniciar sesión'
        commit('SET_ERROR', msg)
        throw new Error(msg)
      } finally {
        commit('SET_LOADING', false)
      }
    },

    logout({ commit }) {
      commit('LOGOUT')
    },

    async cambiarTrimestre({ commit, state, dispatch }, trimestre) {
      commit('SET_TRIMESTRE', trimestre)
      if (!state.salesData[trimestre]) {
        await dispatch('fetchSalesData', trimestre)
      }
    },

    async fetchSalesData({ commit, state }) {
      commit('SET_LOADING', true)
      try {
        const config = { headers: { Authorization: `Bearer ${state.token}` } }
        const response = await axios.get(`${API_URL}/sales/${state.trimestre}`, config)
        commit('SET_SALES_DATA', { quarter: state.trimestre, data: response.data })
      } catch (error) {
        commit('SET_ERROR', 'Error al cargar datos de ventas.')
        console.error('API Error:', error)
      } finally {
        commit('SET_LOADING', false)
      }
    },

    async fetchUsers({ commit, state }) {
      commit('SET_LOADING', true)
      try {
        const config = { headers: { Authorization: `Bearer ${state.token}` } }
        const response = await axios.get(`${API_URL}/users`, config)
        commit('SET_USERS', response.data)
      } catch (error) {
        commit('SET_ERROR', 'Error al cargar los usuarios.')
        console.error('API Error:', error)
      } finally {
        commit('SET_LOADING', false)
      }
    }
  }
})
